// ──────────────────────────────────────────────────────────────────────
// Helpers
// ──────────────────────────────────────────────────────────────────────

// Get current Ayurvedic season based on the calendar month
export function getCurrentSeason() {
  const month = new Date().getMonth() + 1; // 1-12
  if (month === 11 || month === 12) return 'HEMANTA';
  if (month === 1 || month === 2)   return 'SHISHIRA';
  if (month === 3 || month === 4)   return 'VASANTA';
  if (month === 5 || month === 6)   return 'GRISHMA';
  if (month === 7 || month === 8)   return 'VARSHA';
  return 'SHARAD'; // Sep-Oct
}

// Get day of year (1-366), used to deterministically pick the day's tip
export function getDayOfYear(d = new Date()) {
  const start = new Date(d.getFullYear(), 0, 0);
  const diff = d - start;
  return Math.floor(diff / (1000 * 60 * 60 * 24));
}

// Resolve today's tip for a patient given their Prakriti.
// `prakriti` may be 'VATA' | 'PITTA' | 'KAPHA' (any case) or null/undefined/anything else.
// Returns { tip, prakriti, season } where prakriti is the resolved bucket
// ('VATA' / 'PITTA' / 'KAPHA' / 'GENERAL') and season is the current Ayurvedic season.
export function getTipForPatient(prakriti, dayOfYear) {
  const season = getCurrentSeason();
  const upper = typeof prakriti === 'string' ? prakriti.toUpperCase() : null;
  const dosha = ['VATA', 'PITTA', 'KAPHA'].includes(upper) ? upper : null;

  if (dosha) {
    const tips = AYURVEDIC_TIPS[dosha][season];
    return {
      tip: tips[dayOfYear % tips.length],
      prakriti: dosha,
      season,
    };
  }

  const tips = AYURVEDIC_TIPS.GENERAL;
  return {
    tip: tips[dayOfYear % tips.length],
    prakriti: 'GENERAL',
    season,
  };
}
